import pico_ioc as pico
import services
import schemas
import pico_pydantic
from pico_pydantic import ValidationFailedError

pico.init(modules=[pico_pydantic, services])
svc = pico.get(services.OrderService)

def test_valid_order():
    result = svc.place_order({"product": "Laptop", "quantity": 2, "price_per_unit": 999.99})
    assert "Laptop" in result
    print(f"PASS: {result}")

def test_empty_product():
    try:
        svc.place_order({"product": "   ", "quantity": 1, "price_per_unit": 10.0})
        assert False, "Should have raised"
    except ValidationFailedError:
        print("PASS: Blank product rejected")

def test_zero_quantity():
    try:
        svc.place_order({"product": "Mouse", "quantity": 0, "price_per_unit": 25.0})
        assert False, "Should have raised"
    except ValidationFailedError:
        print("PASS: Zero quantity rejected")

def test_negative_price():
    try:
        svc.place_order({"product": "Keyboard", "quantity": 1, "price_per_unit": -5.0})
        assert False, "Should have raised"
    except ValidationFailedError:
        print("PASS: Negative price rejected")

