from pico_ioc import component, interceptor, intercepted_by, Invocation
from pico_pydantic import validate
from schemas import PaymentData

@interceptor
class LoggingInterceptor:
    def intercept(self, invocation: Invocation):
        method_name = invocation.method.__name__
        print(f"[LOG] Calling {method_name} with args={invocation.args}")
        result = invocation.proceed()
        print(f"[LOG] {method_name} returned: {result}")
        return result

@component
class PaymentService:
    @validate
    @intercepted_by(LoggingInterceptor)
    def process_payment(self, data: PaymentData) -> str:
        return f"Processed {data.amount} {data.currency}"
